// ── Yardımcı fonksiyonlar ───────────────────────────────────────────────
List<Cevap> getCevapBySection(String sec) =>
    allCevaplar.where((c) => c.section == sec).toList();

List<Cevap> searchCevap(String q) {
  final lower = q.toLowerCase();
  return allCevaplar.where((c) =>
    c.title.toLowerCase().contains(lower) ||
    c.shortAnswer.toLowerCase().contains(lower) ||
    c.tags.any((t) => t.toLowerCase().contains(lower)),
  ).toList();
}

List<Cevap> getRecommendedCevap() {
  const ids = ['CEVAP-0001', 'CEVAP-0101', 'CEVAP-0201', 'CEVAP-0301', 'CEVAP-0401', 'CEVAP-0501', 'CEVAP-0601', 'CEVAP-0701', 'CEVAP-0801', 'CEVAP-0901', 'CEVAP-0010', 'CEVAP-0110'];
  return ids
      .map((id) => allCevaplar.firstWhere(
        (c) => c.id == id,
        orElse: () => allCevaplar.first,
      ))
      .toList();
}
